/* 바디코드에 JS로 적용 (SPA 대응) */
<script>
const observer = new MutationObserver(() => {
  document.querySelectorAll('TARGET_SELECTOR').forEach(el => {
    if (el.textContent.includes('숨길 텍스트')) {
      el.style.display = 'none';
    }
  });
});
observer.observe(document.body, { childList: true, subtree: true });
</script>
